#include <iostream>
#include <sstream>
#include <iomanip>
#include <string>

class Shape
{
public:
    virtual Shape* clone() const { return new Shape{ *this }; }
    virtual std::string describe() const { return "Shape"; }
    virtual void scale(double) {}
};

class Circle : public Shape
{
    double m_radius{};

public:
    Circle(double radius)
        : m_radius{ radius }
    {
    }

    Circle* clone() const override final { return new Circle{ *this }; }

    void scale(double factor) override { m_radius *= factor; }

    std::string describe() const override
    {
        std::ostringstream oss{};
        oss << "Circle r=" << std::fixed << std::setprecision(1) << m_radius;
        return oss.str();
    }
};

class Square : public Shape
{
    double m_side{};

public:
    Square(double side)
        : m_side{ side }
    {
    }

    Square* clone() const override { return new Square{ *this }; }

    void scale(double factor) override { m_side *= factor; }

    std::string describe() const override
    {
        std::ostringstream oss{};
        oss << "Square s=" << std::fixed << std::setprecision(1) << m_side;
        return oss.str();
    }
};

int main()
{
    std::string type{};
    double value{};
    double factor{};
    std::cin >> type >> value >> factor;

    Shape* original{ nullptr };
    if (type == "circle")
        original = new Circle{ value };
    else
        original = new Square{ value };

    Shape* copy{ original->clone() };

    original->scale(factor);

    std::cout << "clone: " << copy->describe() << '\n';
    std::cout << "original: " << original->describe() << '\n';

    delete copy;
    delete original;

    return 0;
}
